import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Swal from "sweetalert2";
import "./brackets.css";

const TournamentBrackets = () => {
  const [teams, setTeams] = useState([]);
  const [isAdmin, setIsAdmin] = useState(false);
  const [results, setResults] = useState(() => {
    return JSON.parse(localStorage.getItem("tournamentResults")) || {};
  });

  const navigate = useNavigate();

  useEffect(() => {
    const savedTeams = JSON.parse(localStorage.getItem("generatedTeams")) || [];
    setTeams(savedTeams);
    // ž¦┘äž¬žŻ┘āž» ┘ģ┘å žŁž¦┘äž® ž¦┘äžŻž»┘ģ┘å
    setIsAdmin(localStorage.getItem("isAdmin") === "true");
  }, []);

  useEffect(() => {
    localStorage.setItem("tournamentResults", JSON.stringify(results));
  }, [results]);

  const handleWin = (matchId, winnerIdx, loserIdx, mode) => {
    if (!isAdmin) return;

    Swal.fire({
      title: `ž¬žŻ┘ā┘Ŗž» ┘ü┘łž▓ ž¦┘ä┘üž▒┘Ŗ┘é ${winnerIdx + 1}ž¤`,
      icon: "trophy",
      background: "#0f172a",
      color: "#fff",
      showCancelButton: true,
      confirmButtonText: "ž¬žŻ┘ā┘Ŗž» ž¦┘ä┘åž¬┘Ŗž¼ž®",
      cancelButtonText: "žź┘äž║ž¦žĪ",
      confirmButtonColor: "#3b82f6",
    }).then((result) => {
      if (result.isConfirmed) {
        const newResults = { ...results };
        if (mode === "LEAGUE") {
          newResults[`team_${winnerIdx}_points`] =
            (newResults[`team_${winnerIdx}_points`] || 0) + 3;
          newResults[`team_${winnerIdx}_played`] =
            (newResults[`team_${winnerIdx}_played`] || 0) + 1;
          newResults[`team_${loserIdx}_played`] =
            (newResults[`team_${loserIdx}_played`] || 0) + 1;
          newResults[`match_${matchId}_done`] = true;
          newResults[`match_${matchId}_winner`] = winnerIdx;
        } else {
          newResults[`match_${matchId}_winner`] = winnerIdx;
          newResults[`match_${matchId}_loser`] = loserIdx;
        }
        setResults(newResults);
      }
    });
  };

  const resetTournament = () => {
    Swal.fire({
      title: "ž¬žĄ┘ü┘Ŗž▒ ž¦┘ä┘åž¬ž¦ž”ž¼ž¤",
      text: "ž│┘Ŗž¬┘ģ žŁž░┘ü ž¼┘ģ┘Ŗž╣ ┘åž¬ž¦ž”ž¼ ž¦┘ä┘ģž©ž¦ž▒┘Ŗž¦ž¬ ž¦┘äžŁž¦┘ä┘Ŗž®!",
      icon: "warning",
      showCancelButton: true,
      background: "#0f172a",
      color: "#fff",
      confirmButtonText: "┘åž╣┘ģžī žĄ┘üž▒┘ćž¦",
    }).then((res) => {
      if (res.isConfirmed) {
        setResults({});
        localStorage.removeItem("tournamentResults");
      }
    });
  };

  const numTeams = teams.length;

  return (
    <div className="bracket-wrapper">
      <div className="header-actions">
        <button className="back-btn" onClick={() => navigate("/teams-reveal")}>
          ŌåÉ ž¦┘ä┘üž▒┘é
        </button>
        <h1>
          TOURNAMENT <span>HUB</span>
        </h1>
        {isAdmin && (
          <button className="reset-btn" onClick={resetTournament}>
            Reset ­¤öä
          </button>
        )}
      </div>

      {/* ┘åžĖž¦┘ģ ž¦┘ä┘å┘éž¦žĘ (3 žŻ┘ł 5 ┘üž▒┘é) */}
      {(numTeams === 3 || numTeams === 5) && (
        <div className="league-container">
          <div className="standings-card">
            <h3>ž¦┘äž¬ž▒ž¬┘Ŗž© ž¦┘äžŁž¦┘ä┘Ŗ</h3>
            <table>
              <thead>
                <tr>
                  <th>ž¦┘ä┘üž▒┘Ŗ┘é</th>
                  <th>┘äž╣ž©</th>
                  <th>┘å┘éž¦žĘ</th>
                </tr>
              </thead>
              <tbody>
                {teams.map((_, i) => (
                  <tr key={i}>
                    <td>TEAM {i + 1}</td>
                    <td>{results[`team_${i}_played`] || 0}</td>
                    <td className="pts">{results[`team_${i}_points`] || 0}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="fixtures-list">
            <h3>ž¦┘ä┘ģ┘łž¦ž¼┘ćž¦ž¬</h3>
            {generateLeagueMatches(numTeams).map((m, idx) => (
              <div
                className={`match-bar ${results[`match_${idx}_done`] ? "finished" : ""}`}
                key={idx}
              >
                <div
                  className={`t-name ${results[`match_${idx}_winner`] === m.t1 ? "gold" : ""}`}
                >
                  TEAM {m.t1 + 1}
                  {isAdmin && !results[`match_${idx}_done`] && (
                    <button
                      onClick={() => handleWin(idx, m.t1, m.t2, "LEAGUE")}
                    >
                      ­¤Åå
                    </button>
                  )}
                </div>
                <div className="vs-label">VS</div>
                <div
                  className={`t-name ${results[`match_${idx}_winner`] === m.t2 ? "gold" : ""}`}
                >
                  TEAM {m.t2 + 1}
                  {isAdmin && !results[`match_${idx}_done`] && (
                    <button
                      onClick={() => handleWin(idx, m.t2, m.t1, "LEAGUE")}
                    >
                      ­¤Åå
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ┘åžĖž¦┘ģ ž¦┘äž┤ž¼ž▒ž® ž¦┘ä┘ģžĘ┘łž▒ ┘ä┘Ć 4 ┘üž▒┘é */}
      {numTeams === 4 && (
        <div className="double-elim-container">
          <div className="bracket-column">
            <h4 className="b-title">WINNERS BRACKET</h4>
            <MatchNode
              id="m1"
              t1={0}
              t2={3}
              results={results}
              handleWin={handleWin}
              isAdmin={isAdmin}
              teams={teams}
            />
            <MatchNode
              id="m2"
              t1={1}
              t2={2}
              results={results}
              handleWin={handleWin}
              isAdmin={isAdmin}
              teams={teams}
            />
            <div className="match-node final-win">
              <MatchNode
                id="win_final"
                t1={results.match_m1_winner}
                t2={results.match_m2_winner}
                results={results}
                handleWin={handleWin}
                isAdmin={isAdmin}
                teams={teams}
                label="┘å┘ćž¦ž”┘Ŗ ž¦┘ä┘üž¦ž”ž▓┘Ŗ┘å"
              />
            </div>
          </div>

          <div className="bracket-column">
            <h4 className="b-title">LOSERS BRACKET</h4>
            <MatchNode
              id="lose_1"
              t1={results.match_m1_loser}
              t2={results.match_m2_loser}
              results={results}
              handleWin={handleWin}
              isAdmin={isAdmin}
              teams={teams}
              label="┘åžĄ┘ü ┘å┘ćž¦ž”┘Ŗ ž¦┘äž«ž¦ž│ž▒┘Ŗ┘å"
            />
            <MatchNode
              id="lose_final"
              t1={results.match_lose_1_winner}
              t2={results.match_win_final_loser}
              results={results}
              handleWin={handleWin}
              isAdmin={isAdmin}
              teams={teams}
              label="┘å┘ćž¦ž”┘Ŗ ž¦┘äž«ž¦ž│ž▒┘Ŗ┘å"
            />
          </div>

          <div className="bracket-column grand-final">
            <h4 className="b-title">GRAND FINAL</h4>
            <MatchNode
              id="grand_final"
              t1={results.match_win_final_winner}
              t2={results.match_lose_final_winner}
              results={results}
              handleWin={handleWin}
              isAdmin={isAdmin}
              teams={teams}
              label="ž¦┘ä┘ģž©ž¦ž▒ž¦ž® ž¦┘ä┘å┘ćž¦ž”┘Ŗž®"
            />
          </div>
        </div>
      )}
    </div>
  );
};

const MatchNode = ({
  id,
  t1,
  t2,
  results,
  handleWin,
  isAdmin,
  teams,
  label,
}) => {
  const winner = results[`match_${id}_winner`];
  return (
    <div className="node-card">
      {label && <span className="node-label">{label}</span>}
      <div
        className={`node-team ${winner === t1 && t1 !== undefined ? "won" : ""}`}
      >
        {t1 !== undefined ? `TEAM ${t1 + 1}` : "ŌÅ│"}
        {isAdmin &&
          winner === undefined &&
          t1 !== undefined &&
          t2 !== undefined && (
            <button onClick={() => handleWin(id, t1, t2, "TREE")}>Ō£ō</button>
          )}
      </div>
      <div
        className={`node-team ${winner === t2 && t2 !== undefined ? "won" : ""}`}
      >
        {t2 !== undefined ? `TEAM ${t2 + 1}` : "ŌÅ│"}
        {isAdmin &&
          winner === undefined &&
          t1 !== undefined &&
          t2 !== undefined && (
            <button onClick={() => handleWin(id, t2, t1, "TREE")}>Ō£ō</button>
          )}
      </div>
    </div>
  );
};

const generateLeagueMatches = (n) => {
  let m = [];
  for (let i = 0; i < n; i++) {
    for (let j = i + 1; j < n; j++) m.push({ t1: i, t2: j });
  }
  return m;
};

export default TournamentBrackets;
