import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import Swal from "sweetalert2";
import "./waiting.css";

const API_BASE_URL = "https://mlbb-production-ffdf.up.railway.app/api";

const Waiting = () => {
  const [players, setPlayers] = useState([]);
  const [isAdmin, setIsAdmin] = useState(false);
  const [regOpen, setRegOpen] = useState(true);
  const [clickCount, setClickCount] = useState(0);
  const navigate = useNavigate();

  const fetchData = useCallback(async () => {
    try {
      const token = localStorage.getItem("token");
      if (!token) {
        navigate("/");
        return;
      }

      // 1. ┘üžŁžĄ ž¦┘ä┘ć┘ł┘Ŗž® (┘ä┘äžĘž▒ž» ž¦┘äž¬┘ä┘éž¦ž”┘Ŗ žźž░ž¦ ž¬┘ģ žŁž░┘ü ž¦┘ä┘äž¦ž╣ž©)
      await axios.get(`${API_BASE_URL}/me`, {
        headers: { Authorization: `Bearer ${token}` },
      });

      // 2. ž¼┘äž© ž¦┘ä┘äž¦ž╣ž©┘Ŗ┘å ┘łž¦┘äžźž╣ž»ž¦ž»ž¦ž¬
      const pRes = await axios.get(`${API_BASE_URL}/players`);
      const sRes = await axios.get(`${API_BASE_URL}/settings`);

      setPlayers(pRes.data);
      setRegOpen(sRes.data.registration_open !== false);

      // žźž░ž¦ ž©ž»žŻ ž¦┘äžŻž»┘ģ┘å ┘āž┤┘ü ž¦┘ä┘üž▒┘éžī ž¦┘å┘é┘ä ž¦┘ä┘äž¦ž╣ž©┘Ŗ┘å ž¦┘äž╣ž¦ž»┘Ŗ┘Ŗ┘å ž¬┘ä┘éž¦ž”┘Ŗž¦┘ŗ
      const currentAdmin = localStorage.getItem("isAdmin") === "true";
      if (!currentAdmin && sRes.data.reveal_started) {
        navigate("/teams-reveal");
      }
    } catch (err) {
      if (
        err.response &&
        (err.response.status === 404 || err.response.status === 403)
      ) {
        localStorage.removeItem("token");
        navigate("/");
      }
    }
  }, [navigate]);

  useEffect(() => {
    if (localStorage.getItem("isAdmin") === "true") setIsAdmin(true);
    fetchData();
    const interval = setInterval(fetchData, 2000);
    return () => clearInterval(interval);
  }, [fetchData]);

  // ž»ž¦┘äž® ┘é┘ü┘ä/┘üž¬žŁ ž¦┘äž¬ž│ž¼┘Ŗ┘ä
  const toggleReg = async () => {
    try {
      const res = await axios.post(`${API_BASE_URL}/toggle-reg`);
      setRegOpen(res.data.registration_open);
      Swal.fire({
        title: res.data.registration_open
          ? "ž¬┘ģ ┘üž¬žŁ ž¦┘äž¬ž│ž¼┘Ŗ┘ä Ō£ģ"
          : "ž¬┘ģ žźž║┘äž¦┘é ž¦┘äž¬ž│ž¼┘Ŗ┘ä ­¤öÆ",
        icon: "info",
        background: "#0f172a",
        color: "#fff",
        confirmButtonColor: "#3b82f6",
      });
    } catch (err) {
      Swal.fire("ž«žĘžŻ", "┘üž┤┘ä ž¬ž║┘Ŗ┘Ŗž▒ žŁž¦┘äž® ž¦┘äž¬ž│ž¼┘Ŗ┘ä", "error");
    }
  };

  // ž»ž¦┘äž® žŁž░┘ü ┘äž¦ž╣ž© ┘ģž╣ ž¬žŻ┘ā┘Ŗž»
  const handleDeletePlayer = async (id, name) => {
    const result = await Swal.fire({
      title: `žŁž░┘ü ${name}ž¤`,
      text: "┘ä┘å ┘Ŗž¬┘ģ┘ā┘å ž¦┘ä┘äž¦ž╣ž© ┘ģ┘å ž¦┘äž╣┘łž»ž® žź┘äž¦ ž©ž¦┘äž¬ž│ž¼┘Ŗ┘ä ┘ģž¼ž»ž»ž¦┘ŗ",
      icon: "warning",
      showCancelButton: true,
      confirmButtonText: "┘åž╣┘ģžī ž¦žŁž░┘ü┘ć",
      cancelButtonText: "žź┘äž║ž¦žĪ",
      background: "#0f172a",
      color: "#fff",
      confirmButtonColor: "#ef4444",
    });

    if (result.isConfirmed) {
      try {
        await axios.delete(`${API_BASE_URL}/players/${id}`);
        fetchData();
      } catch (err) {
        Swal.fire("ž«žĘžŻ", "┘üž┤┘ä žŁž░┘ü ž¦┘ä┘äž¦ž╣ž©", "error");
      }
    }
  };

  const handleAdminClick = () => {
    setClickCount((p) => {
      if (p + 1 === 5) {
        showPasswordAlert();
        return 0;
      }
      return p + 1;
    });
  };

  const showPasswordAlert = async () => {
    const { value: pass } = await Swal.fire({
      title: "ž»ž«┘ł┘ä ž¦┘äžźž»ž¦ž▒ž®",
      input: "password",
      background: "#0f172a",
      color: "#fff",
      confirmButtonColor: "#3b82f6",
    });
    if (pass === "8520085") {
      localStorage.setItem("isAdmin", "true");
      setIsAdmin(true);
      fetchData();
    }
  };

  const startReveal = async () => {
    try {
      await axios.post(`${API_BASE_URL}/start-reveal`);
      navigate("/teams-reveal");
    } catch (err) {
      Swal.fire("ž«žĘžŻ", "┘üž┤┘ä ž¦┘äž©ž»žĪ", "error");
    }
  };

  const resetTournament = async () => {
    const result = await Swal.fire({
      title: "ž¬žĄ┘ü┘Ŗž▒ ž¦┘äž©žĘ┘ł┘äž® ž©ž¦┘ä┘āž¦┘ģ┘äž¤",
      text: "ž│┘Ŗž¬┘ģ žŁž░┘ü ž¼┘ģ┘Ŗž╣ ž¦┘ä┘äž¦ž╣ž©┘Ŗ┘å ┘ł┘üž¬žŁ ž¦┘äž¬ž│ž¼┘Ŗ┘ä ┘ģ┘å ž¼ž»┘Ŗž»",
      icon: "warning",
      showCancelButton: true,
      confirmButtonText: "┘åž╣┘ģžī žĄ┘üž▒ ž¦┘ä┘ā┘ä",
      background: "#0f172a",
      color: "#fff",
      confirmButtonColor: "#ef4444",
    });
    if (result.isConfirmed) {
      try {
        await axios.post(`${API_BASE_URL}/reset`);
        fetchData();
      } catch (err) {
        console.error(err);
      }
    }
  };

  return (
    <div className="waiting-wrapper">
      <div className="waiting-container">
        <div className="waiting-header">
          <h2 onClick={handleAdminClick} style={{ cursor: "pointer" }}>
            <span>MLBB</span> Waiting
          </h2>
          <div className="status-badges">
            <div className="counter-badge">ž¦┘äžŻž©žĘž¦┘ä: {players.length}</div>
            <div className={`reg-badge ${regOpen ? "open" : "closed"}`}>
              {regOpen ? "ž¦┘äž¬ž│ž¼┘Ŗ┘ä ┘ģž¬ž¦žŁ" : "ž¦┘äž¬ž│ž¼┘Ŗ┘ä ┘ģž║┘ä┘é"}
            </div>
          </div>
        </div>

        <div className="players-grid">
          {players.length === 0 ? (
            <div className="empty-state">
              <div className="mlbb-spinner"></div>
              <p>ž©ž¦┘åž¬žĖž¦ž▒ ž»ž«┘ł┘ä ž¦┘äžŻž©žĘž¦┘ä...</p>
            </div>
          ) : (
            <table className="players-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>ž¦┘äž¦ž│┘ģ</th>
                  {isAdmin && <th>ž¬žŁ┘ā┘ģ</th>}
                </tr>
              </thead>
              <tbody>
                {players.map((p, i) => (
                  <tr key={p._id || i}>
                    <td>{i + 1}</td>
                    <td>{p.name}</td>
                    {isAdmin && (
                      <td>
                        <button
                          className="del-icon"
                          onClick={() => handleDeletePlayer(p._id, p.name)}
                        >
                          ŌØī
                        </button>
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        {isAdmin && (
          <div className="admin-footer-controls">
            <button
              onClick={toggleReg}
              className={`admin-btn ${regOpen ? "lock" : "unlock"}`}
            >
              {regOpen ? "┘é┘ü┘ä ž¦┘äž¬ž│ž¼┘Ŗ┘ä ­¤öÆ" : "┘üž¬žŁ ž¦┘äž¬ž│ž¼┘Ŗ┘ä ­¤öō"}
            </button>
            <button onClick={startReveal} className="admin-btn edit">
              ž¦ž©ž»žŻ ž¦┘äž¬ž┤┘ā┘Ŗ┘ä ­¤ÜĆ
            </button>
            <button onClick={resetTournament} className="admin-btn reset">
              ž¬žĄ┘ü┘Ŗž▒ ­¤Śæ’ĖÅ
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Waiting;
